const express = require("express");
const app = express();

app.use(express.urlencoded({ extended: true }));

// ===== MAIN AI FUNCTION =====
function getHaithamResponse(msg) {
  msg = msg.toLowerCase();

  // ===== MAIN MENU =====
  if (msg === "hi" || msg === "hello" || msg === "habari") {
    return `Karibu Tilla Insurance Agency 👋
Naitwa Haitham.

Chagua huduma:
1️⃣ Bima
2️⃣ LATRA
3️⃣ TIN
4️⃣ TRA/BRELA`;
  }

  // ===== BIMA =====
  if (msg.includes("bima")) {
    return `Unahitaji bima gani?
1️⃣ Third Party
2️⃣ Comprehensive`;
  }

  // ===== THIRD PARTY =====
  if (msg === "1") {
    return `Niambie:
- Aina ya chombo
- Matumizi (binafsi/biashara)
- Kama ni basi, ni siti ngapi`;
  }

  // ===== DALADALA =====
  if (msg.includes("daladala")) {
    let seats = extractNumber(msg);
    if (seats) {
      let price = seats * 17700;
      return `Daladala siti ${seats}
💰 TSh ${price}

Tuanze mchakato? 👍`;
    }
    return "Niambie daladala lina siti ngapi?";
  }

  // ===== SCHOOL BUS =====
  if (msg.includes("school")) {
    let seats = extractNumber(msg);
    if (seats) {
      let price = seats * 8850;
      return `School Bus siti ${seats}
💰 TSh ${price}`;
    }
    return "Niambie lina siti ngapi?";
  }

  // ===== STAFF BUS =====
  if (msg.includes("staff")) {
    let seats = extractNumber(msg);
    if (seats) {
      let price = seats * 11800;
      return `Staff Bus siti ${seats}
💰 TSh ${price}`;
    }
    return "Niambie lina siti ngapi?";
  }

  // ===== MABASI YA MKOA =====
  if (msg.includes("mkoa")) {
    let seats = extractNumber(msg);
    if (seats) {
      let price = seats * 35400;
      return `Basi la Mkoa siti ${seats}
💰 TSh ${price}`;
    }
    return "Niambie lina siti ngapi?";
  }

  // ===== COMPREHENSIVE =====
  if (msg.includes("2")) {
    return `Tafadhali tuma:
- Namba ya gari
- Jina
- TIN
- Thamani ya gari
- Simu`;
  }

  // ===== LATRA =====
  if (msg.includes("latra")) {
    return `Mahitaji ya LATRA:
1. NIDA
2. Kadi ya gari
3. Bima

Una bima tayari?`;
  }

  // ===== TIN =====
  if (msg.includes("tin")) {
    return `Tafadhali tuma:
- Jina kamili
- NIDA
- Mama/Baba
- DOB
- Simu`;
  }

  // ===== TRA/BRELA =====
  if (msg.includes("brela") || msg.includes("tra")) {
    return `Utapigiwa muda mfupi kwa maelezo zaidi 👍`;
  }

  return "Samahani, tafadhali chagua huduma (1-4)";
}

// ===== HELPER =====
function extractNumber(text) {
  const match = text.match(/\d+/);
  return match ? parseInt(match[0]) : null;
}

// ===== WEBHOOK =====
app.post("/webhook", (req, res) => {
  const incomingMsg = req.body.Body;

  const reply = getHaithamResponse(incomingMsg);

  res.set("Content-Type", "text/xml");
  res.send(`
    <Response>
      <Message>${reply}</Message>
    </Response>
  `);
});

app.listen(3000, () => console.log("Haitham is running 🚀"));

Your code is a simple Node.js Express chatbot web service for Tilla Insurance Agency, responding in Swahili. Here's a summary of what it does:

- **Main logic:** Handles insurance, LATRA, TIN, TRA/BRELA queries.
- **User session state:** _Stateless_ (no memory of previous answers). Each message triggers a new flow based solely on user input.

## Review & Recommendations

### 1. Functionality

**Works:**  
- Main menu, bima type selection, pricing based on seats for various bus types, LATRA, TIN, TRA/BRELA info.
- Handles webhook receives and replies with Twilio-style XML `<Response>`.

**Improvements:**
- Selection by input (e.g., `1`) is ambiguous because the code for "1" triggers _Third Party_ details only if the exact input is received, even if the context was not about bima.
- No session/step tracking: After "1", if a user just writes "daladala 24", it works, but if they write "2" (Comprehensive), it will always go to the comprehensive details wherever "2" appears—might introduce confusion.
- For car insurance, no pricing or further interaction—could prompt for more info and confirm receipt.

### 2. Safety & Bugs

- Main bug: `if (msg.includes("2"))` matches any message with "2", so e.g. "staff bus 22" triggers comprehensive flow.
- If the user types, for example, "Hi 1" or "bima 1", it won't work as expected.

