    sessionState.state = "TIN";
    return `Tafadhali tuma:
- Jina kamili
- NIDA
- Mama/Baba
- DOB
- Simu`;
  }
  if (["4", "brela", "tra"].some((x) => msg.includes(x))) {
    sessionState.state = "TRA_BRELA";
    return `Utapigiwa muda mfupi kwa maelezo zaidi 👍`;
