        return `Daladala siti ${seats}
💰 TSh ${price}

Tuanze mchakato? 👍`;
      }
      return "Niambie daladala lina siti ngapi?";
    }
    if (msg.includes("school")) {
      let seats = extractNumber(msg);
      if (seats) {
        let price = seats * 8850;
        sessionState.bimaStage = null;
        return `School Bus siti ${seats}
💰 TSh ${price}`;
      }
      return "Niambie lina siti ngapi?";
    }
    if (msg.includes("staff")) {
      let seats = extractNumber(msg);
      if (seats) {
